INSERT INTO t_paper_voting_delivery (
    package_id, electorate_item_id, tenant_id, proxy_authorization_id, recipient_name, delivery_method,
    evidence_source_type, evidence_source_id, evidence_hash,
    delivered_by_user_id, delivered_at, status
) VALUES (
    #{packageId}, #{electorateItemId}, #{tenantId}, #{proxyAuthorizationId}, #{recipientName}, #{deliveryMethod},
    #{evidenceSourceType}, #{evidenceSourceId}, #{evidenceHash},
    #{deliveredByUserId}, #{deliveredAt}, #{status}
)

mapper.select:
SELECT 
FROM t_paper_voting_delivery delivery
JOIN t_voting_electorate_item_snapshot electorate
  ON electorate.snapshot_item_id = delivery.electorate_item_id
WHERE delivery.paper_delivery_id = #{paperDeliveryId}
  AND delivery.package_id = #{packageId}
  AND delivery.tenant_id = #{tenantId}

SELECT 
FROM t_paper_voting_delivery delivery
JOIN t_voting_electorate_item_snapshot electorate
  ON electorate.snapshot_item_id = delivery.electorate_item_id
WHERE delivery.paper_delivery_id = #{paperDeliveryId}
  AND delivery.package_id = #{packageId}
  AND delivery.tenant_id = #{tenantId}
FOR UPDATE OF delivery

mapper.update:
UPDATE t_paper_voting_delivery
SET status = 'CONFIRMED', reviewed_by_user_id = #{reviewedByUserId},
    reviewed_at = #{reviewedAt}, unified_delivery_id = #{unifiedDeliveryId},
    update_time = CURRENT_TIMESTAMP, version = version + 1
WHERE paper_delivery_id = #{paperDeliveryId}
  AND tenant_id = #{tenantId}
  AND status = 'PENDING_REVIEW'
  AND version = #{expectedVersion}

UPDATE t_paper_voting_delivery
SET status = 'REJECTED', reviewed_by_user_id = #{reviewedByUserId},
    reviewed_at = #{reviewedAt}, review_note = #{reviewNote},
    update_time = CURRENT_TIMESTAMP, version = version + 1
WHERE paper_delivery_id = #{paperDeliveryId}
  AND tenant_id = #{tenantId}
  AND status = 'PENDING_REVIEW'
  AND version = #{expectedVersion}

