    paper_ballot_id, tenant_id, version_number, status, entered_by_user_id, entered_at
) VALUES (
    #{paperBallotId}, #{tenantId}, #{versionNumber}, #{status}, #{enteredByUserId}, #{enteredAt}
)

mapper.select:
SELECT entry_id, paper_ballot_id, tenant_id, version_number, status,
       entered_by_user_id, entered_at, reviewed_by_user_id, reviewed_at, review_note
FROM t_paper_ballot_entry
WHERE entry_id = #{entryId}
  AND paper_ballot_id = #{paperBallotId}
  AND tenant_id = #{tenantId}

SELECT entry_id, paper_ballot_id, tenant_id, version_number, status,
       entered_by_user_id, entered_at, reviewed_by_user_id, reviewed_at, review_note
FROM t_paper_ballot_entry
WHERE entry_id = #{entryId}
  AND paper_ballot_id = #{paperBallotId}
  AND tenant_id = #{tenantId}
FOR UPDATE

SELECT COALESCE(MAX(version_number), 0) + 1
FROM t_paper_ballot_entry
WHERE paper_ballot_id = #{paperBallotId} AND tenant_id = #{tenantId}

mapper.update:
UPDATE t_paper_ballot_entry
SET status = 'CONFIRMED', reviewed_by_user_id = #{reviewedByUserId},
    reviewed_at = #{reviewedAt}
WHERE entry_id = #{entryId}
  AND tenant_id = #{tenantId}
  AND status = 'PENDING_REVIEW'
  AND entered_by_user_id <> #{reviewedByUserId}

UPDATE t_paper_ballot_entry
SET status = 'REJECTED', reviewed_by_user_id = #{reviewedByUserId},
    reviewed_at = #{reviewedAt}, review_note = #{reviewNote}
WHERE entry_id = #{entryId}
  AND tenant_id = #{tenantId}
  AND status = 'PENDING_REVIEW'
  AND entered_by_user_id <> #{reviewedByUserId}

