INSERT INTO t_paper_ballot_outcome (
    paper_ballot_id, entry_id, subject_id, status, unified_ballot_id,
    conflicting_ballot_id, reason, finalized_at
) VALUES (
    #{paperBallotId}, #{entryId}, #{subjectId}, #{status}, #{unifiedBallotId},
    #{conflictingBallotId}, #{reason}, #{finalizedAt}
)
ON CONFLICT (paper_ballot_id, subject_id) DO NOTHING

mapper.update:
UPDATE t_paper_ballot
SET status = 'IN_ENTRY', update_time = CURRENT_TIMESTAMP, version = version + 1
WHERE paper_ballot_id = #{paperBallotId}
  AND tenant_id = #{tenantId}
  AND status IN ('RECEIVED', 'IN_ENTRY')
  AND version = #{expectedVersion}

UPDATE t_paper_ballot
SET status = 'COMPLETED', update_time = CURRENT_TIMESTAMP, version = version + 1
WHERE paper_ballot_id = #{paperBallotId}
  AND tenant_id = #{tenantId}
  AND status = 'IN_ENTRY'

UPDATE t_paper_ballot
SET status = 'VOIDED', voided_by_user_id = #{voidedByUserId},
    voided_at = #{voidedAt}, void_reason = #{voidReason},
    update_time = CURRENT_TIMESTAMP, version = version + 1
WHERE paper_ballot_id = #{paperBallotId}
  AND tenant_id = #{tenantId}
  AND status = 'RECEIVED'
  AND version = #{expectedVersion}
